INSERT INTO public.arbaeen_love_of_allah (order_number, title, hadith_text, source, hadith_number, review_status, editor_notes) VALUES
(18, 'إن الله يحب سمح البيع والشراء والقضاء', 'حَدَّثَنَا أَبُو كُرَيْبٍ، حَدَّثَنَا إِسْحَاقُ بْنُ سُلَيْمَانَ الرَّازِيُّ، عَنْ مُغِيرَةَ بْنِ مُسْلِمٍ، عَنْ يُونُسَ، عَنِ الْحَسَنِ، عَنْ أَبِي هُرَيْرَةَ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏ "‏ إِنَّ اللَّهَ يُحِبُّ سَمْحَ الْبَيْعِ سَمْحَ الشِّرَاءِ سَمْحَ الْقَضَاءِ ‏"‏ ‏.‏ قَالَ وَفِي الْبَابِ عَنْ جَابِرٍ ‏.‏ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ ‏.‏ وَقَدْ رَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ يُونُسَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ ‏.‏', 'جامع الترمذي', '1319', 'in_review', 'غريب — نص المصدر نفسه يصفه كذلك، يحتاج تحققًا إضافيًا من الدرجة عند المراجعة'),
(19, 'أحب شيء إلى الله: دمعة خشية ودم في سبيله', 'حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ، حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ، أَنْبَأَنَا الْوَلِيدُ بْنُ جَمِيلٍ الْفِلَسْطِينِيُّ، عَنِ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ، عَنْ أَبِي أُمَامَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏ "‏ لَيْسَ شَيْءٌ أَحَبَّ إِلَى اللَّهِ مِنْ قَطْرَتَيْنِ وَأَثَرَيْنِ قَطْرَةٌ مِنْ دُمُوعٍ فِي خَشْيَةِ اللَّهِ وَقَطْرَةُ دَمٍ تُهَرَاقُ فِي سَبِيلِ اللَّهِ ‏.‏ وَأَمَّا الأَثَرَانِ فَأَثَرٌ فِي سَبِيلِ اللَّهِ وَأَثَرٌ فِي فَرِيضَةٍ مِنْ فَرَائِضِ اللَّهِ ‏"‏ ‏.‏ قَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ ‏.‏ ‏', 'جامع الترمذي', '1669', 'in_review', NULL),
(20, 'إن الله يحب أن يرى أثر نعمته على عبده', 'حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ، حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ، حَدَّثَنَا هَمَّامٌ، عَنْ قَتَادَةَ، عَنْ عَمْرِو بْنِ شُعَيْبٍ، عَنْ أَبِيهِ، عَنْ جَدِّهِ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏ "‏ إِنَّ اللَّهَ يُحِبَّ أَنْ يُرَى أَثَرُ نِعْمَتِهِ عَلَى عَبْدِهِ ‏"‏ ‏.‏ وَفِي الْبَابِ عَنْ أَبِي الأَحْوَصِ عَنْ أَبِيهِ وَعِمْرَانَ بْنِ حُصَيْنٍ وَابْنِ مَسْعُودٍ ‏.‏ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ ‏.‏', 'جامع الترمذي', '2819', 'in_review', NULL),
(21, 'أحبوا الله لما يغذوكم من نعمه', 'حَدَّثَنَا أَبُو دَاوُدَ، سُلَيْمَانُ بْنُ الأَشْعَثِ قَالَ أَخْبَرَنَا يَحْيَى بْنُ مَعِينٍ، قَالَ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ، عَنْ عَبْدِ اللَّهِ بْنِ سُلَيْمَانَ النَّوْفَلِيِّ، عَنْ مُحَمَّدِ بْنِ عَلِيِّ بْنِ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ، عَنْ أَبِيهِ، عَنِ ابْنِ عَبَّاسٍ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏ "‏ أَحِبُّوا اللَّهَ لِمَا يَغْذُوكُمْ مِنْ نِعَمِهِ وَأَحِبُّونِي بِحُبِّ اللَّهِ وَأَحِبُّوا أَهْلَ بَيْتِي لِحُبِّي ‏"‏ ‏.‏ قَالَ أَبُو عِيسَى هَذَا ��َدِيثٌ حَسَنٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ هَذَا الْوَجْهِ ‏.‏', 'جامع الترمذي', '3789', 'in_review', NULL),
(22, 'أفضل الأعمال الحب في الله والبغض في الله', 'حَدَّثَنَا مُسَدَّدٌ، حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ، حَدَّثَنَا يَزِيدُ بْنُ أَبِي زِيَادٍ، عَنْ مُجَاهِدٍ، عَنْ رَجُلٍ، عَنْ أَبِي ذَرٍّ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏ "‏ أَفْضَلُ الأَعْمَالِ الْحُبُّ فِي اللَّهِ وَالْبُغْضُ فِي اللَّهِ ‏"‏ ‏.‏', 'سنن أبي داود', '4599', 'in_review', NULL);